double distance(Point const& p1, Point const& p2) {
	return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

double closestPair(std::vector<Point> const& points) {
	if (points.size() < 2) return std::numeric_limits<double>::max(); // Edge case: less than two points

	double min_distance = std::numeric_limits<double>::max();
	int num_threads = omp_get_max_threads();

	// Parallel loop to compute distances between all pairs of points
	#pragma omp parallel for shared(points, min_distance) schedule(static)
	for (int i = 0; i < points.size(); ++i) {
		for (int j = i + 1; j < points.size(); ++j) {
			double dist = distance(points[i], points[j]);
			if (dist < min_distance) { // Update minimum distance if a closer pair is found
				min_distance = dist;
			}
		}
	}

	return min_distance;
}
